function GUILuckyLotteryPanel:onShow()
    if self.isInit then
        return
    end
    self.isInit = true
    self:initList(self.activity.groupId or 2)
    self:setSingleDrawPrice()
    self:setTenDrawPrice()
    self:setLuckValue(self.activity.luckyValue)
end

function GUILuckyLotteryPanel:initEvent()
    self.btnLeft:registerEvent(GUIEvent.ButtonClick, function()
        self:onLottery(1)
    end)
    self.btnRight:registerEvent(GUIEvent.ButtonClick, function()
        self:onLottery(2)
    end)

    self.siRewardShowView:registerEvent(GUIEvent.Click, function()
        self.llRewardShow:SetVisible(false)
        self.llRewardAll:SetVisible(true)
    end)

    self.siRewardBackShow:registerEvent(GUIEvent.Click, function()
        self.llRewardShow:SetVisible(true)
        self.llRewardAll:SetVisible(false)
    end)

    self.llClickBox:registerEvent(GUIEvent.Click, function()
        self.llRewardShow:SetVisible(false)
        self.llRewardAll:SetVisible(true)
    end)

    self.siLuckyBg:registerEvent(GUIEvent.Click, function()
        self.wFloatReward:showDesc("lucky.lottery.ui.desc", self.siLuckyBg)
        self.wFloatRewardNeedShow = true
    end)

    CommonDataEvents:registerCallBack("LuckyLotteryResult", function(data)
        self:showLotteryResult(data)
    end, JsonBuilderProcessor)
end

function GUILuckyLotteryPanel:setSingleDrawPrice()
    ---设置单抽价格
    local priceConfig = LuckyLotteryPriceConfig:getPriceConfigByGroupId(self.activity.priceGroupId)
    local config = priceConfig[1]
    if not config then
        return
    end

    self.siLeftOffBg:SetVisible(false)
    self.siLeftCoolDownIcon:SetVisible(false)
    self.stLeftBtnValue:SetText("")
    self.stLeftBtnPrice:SetText(config.price)
    self.stLeftBtnTopText:SetText(Lang:getString(config.priceLang))

    if config.price > config.discountPrice and ((os.time() - self.activity.lastLotteryTime) > config.discountCycle) then
        self.siLeftOffBg:SetVisible(true)
        self.stLeftOffValue:SetText(math.ceil((config.discountPrice / config.price) * 100) .. "%")
        self.stLeftBtnValue:SetText(config.price)
        self.stLeftBtnPrice:SetText(config.discountPrice)
        self.stLeftBtnValue:SetWidth({ 0, self.stLeftBtnValue:GetFont():GetTextExtent(config.price, 1) })
    elseif config.price > config.discountPrice and ((os.time() - self.activity.lastLotteryTime) < config.discountCycle) then
        self.siLeftCoolDownIcon:SetVisible(true)
        self.stLeftBtnValue:SetWidth({ 0, 0 })

        LuaTimer:cancel(self.LeftBtnKey)
        self.stLeftBtnCoolDownText:SetText(DateUtil.getFormatTime(config.discountCycle - (os.time() - self.activity.lastLotteryTime)))
        self.LeftBtnKey = LuaTimer:scheduleTimer(function()
            self.stLeftBtnCoolDownText:SetText(DateUtil.getFormatTime(config.discountCycle - (os.time() - self.activity.lastLotteryTime)))
        end, 1000, (config.discountCycle - (os.time() - self.activity.lastLotteryTime)))
        self:addTimer(self.LeftBtnKey)
    end

end

